    69→// ComputeAndUpdateSummary processes cases and updates the summary for an error signature
    70→func (sc *SummaryComputer) ComputeAndUpdateSummary(ctx context.Context, lang, signature string) error {
    71→	lockKey := BuildSignatureLockKey(lang, signature)
    72→	lockConfig := DefaultLockConfig()
    73→	lockConfig.DefaultTTL = 10 * time.Second // Longer TTL for summary computation
    74→
    75→	return sc.lockMgr.TryWithLockRetry(ctx, lockKey, lockConfig, func() error {
    76→		return sc.computeAndUpdateSummaryLocked(ctx, lang, signature)
    77→	})
    78→}
