    80→// computeAndUpdateSummaryLocked performs the actual summary computation under lock
    81→func (sc *SummaryComputer) computeAndUpdateSummaryLocked(ctx context.Context, lang, signature string) error {
    82→	// Read all cases for this signature
    83→	cases, err := sc.storage.ReadCases(ctx, lang, signature)
    84→	if err != nil {
    85→		return fmt.Errorf("failed to read cases: %w", err)
    86→	}
    87→
    88→	if len(cases) == 0 {
    89→		return nil // No cases to process
    90→	}
    91→
    92→	// Analyze cases and identify fix candidates
    93→	candidates := sc.analyzeCases(cases)
    94→
    95→	// Score and rank candidates
    96→	scoredCandidates := sc.scoreCandidates(candidates)
    97→
    98→	// Promote top candidates
    99→	promoted := sc.promoteTopCandidates(scoredCandidates)
   100→
   101→	// Compute aggregate statistics
   102→	stats := sc.computeStats(cases)
   103→
   104→	// Create summary record
   105→	summary := &SummaryRecord{
   106→		Language:  lang,
   107→		Signature: signature,
   108→		Promoted:  promoted,
   109→		Stats:     stats,
   110→	}
   111→
   112→	// Store the updated summary
   113→	err = sc.storage.WriteSummary(ctx, lang, signature, summary)
   114→	if err != nil {
   115→		return fmt.Errorf("failed to write summary: %w", err)
   116→	}
   117→
   118→	return nil
   119→}
