   273→// computeStats calculates aggregate statistics for cases
   274→func (sc *SummaryComputer) computeStats(cases []*CaseRecord) *SummaryStats {
   275→	stats := &SummaryStats{
   276→		TotalCases:  len(cases),
   277→		LastUpdated: time.Now(),
   278→	}
   279→
   280→	var totalDuration int64
   281→	var validDurations int
   282→
   283→	for _, caseRecord := range cases {
   284→		if caseRecord.Outcome == nil {
   285→			continue
   286→		}
   287→
   288→		if caseRecord.Outcome.Success {
   289→			stats.SuccessCount++
   290→		} else {
   291→			stats.FailureCount++
   292→		}
   293→
   294→		// Accumulate durations for average calculation
   295→		if caseRecord.Outcome.Duration > 0 {
   296→			totalDuration += caseRecord.Outcome.Duration
   297→			validDurations++
   298→		}
   299→	}
   300→
   301→	// Calculate success rate
   302→	if stats.TotalCases > 0 {
   303→		stats.SuccessRate = float64(stats.SuccessCount) / float64(stats.TotalCases)
   304→	}
   305→
   306→	// Calculate average duration
   307→	if validDurations > 0 {
   308→		stats.AvgDuration = totalDuration / int64(validDurations)
   309→	}
   310→
   311→	return stats
   312→}
