   314→// GetRecommendedFixes retrieves recommended fixes for an error signature
   315→func (sc *SummaryComputer) GetRecommendedFixes(ctx context.Context, lang, signature string, maxResults int) ([]PromotedFix, error) {
   316→	summary, err := sc.storage.ReadSummary(ctx, lang, signature)
   317→	if err != nil {
   318→		return nil, fmt.Errorf("failed to read summary: %w", err)
   319→	}
   320→
   321→	// Return top N promoted fixes
   322→	results := summary.Promoted
   323→	if len(results) > maxResults && maxResults > 0 {
   324→		results = results[:maxResults]
   325→	}
   326→
   327→	return results, nil
   328→}
