   169→// ConvertKBFixesToBranchSpecs converts KB fixes to healing branch specifications
   170→func (kb *KBIntegration) ConvertKBFixesToBranchSpecs(fixes []PromotedFix) []BranchSpec {
   171→	var branches []BranchSpec
   172→
   173→	for i, fix := range fixes {
   174→		branchID := fmt.Sprintf("kb-fix-%d", i)
   175→
   176→		var branchType string
   177→		var inputs map[string]interface{}
   178→
   179→		switch fix.Kind {
   180→		case "orw_recipe":
   181→			branchType = "orw-apply"
   182→			inputs = map[string]interface{}{
   183→				"id":     branchID,
   184→				"type":   "orw-apply",
   185→				"recipe": fix.Ref,
   186→				"source": "kb",
   187→				"score":  fix.Score,
   188→			}
   189→		case "patch_fingerprint":
   190→			branchType = "patch-apply"
   191→			inputs = map[string]interface{}{
   192→				"id":                branchID,
   193→				"type":              "patch-apply",
   194→				"patch_fingerprint": fix.Ref,
   195→				"source":            "kb",
   196→				"score":             fix.Score,
   197→			}
   198→		}
   199→
   200→		branches = append(branches, BranchSpec{
   201→			ID:     branchID,
   202→			Type:   branchType,
   203→			Inputs: inputs,
   204→		})
   205→	}
   206→
   207→	return branches
   208→}
