   224→// SubmitPlannerJob submits a planner job with KB context
   225→func (e *ExtendedJobSubmissionHelper) SubmitPlannerJob(ctx context.Context, config *TransflowConfig, buildError string, workspace string) (*PlanResult, error) {
   226→	// Extract language from config or detect from build error
   227→	language := DetectLanguageFromBuildError(buildError)
   228→
   229→	// Load KB context
   230→	kbCtx, err := e.kb.LoadKBContext(ctx, language, []byte(""), []byte(buildError))
   231→	if err != nil {
   232→		// Continue without KB if loading fails
   233→		return e.original.SubmitPlannerJob(ctx, config, buildError, workspace)
   234→	}
   235→
   236→	// If we have high-confidence KB suggestions, use them directly
   237→	if e.kb.ShouldUseKBSuggestions(kbCtx) {
   238→		// Convert KB fixes to options
   239→		branches := e.kb.ConvertKBFixesToBranchSpecs(kbCtx.RecommendedFixes)
   240→
   241→		// Convert to planner result format
   242→		var options []map[string]interface{}
   243→		for _, branch := range branches {
