   272→	if containsAny(buildError, "tsc", "typescript", "node_modules", "npm", "yarn") {
   273→		return "typescript"
   274→	}
   275→	if containsAny(buildError, "python", "pip", "pytest", "import ") {
   276→		return "python"
   277→	}
   278→	if containsAny(buildError, "rustc", "cargo", "Cargo.toml") {
   279→		return "rust"
   280→	}
   281→
   282→	return "unknown" // Default fallback
   283→}
