   327→// attemptHealingWithKB is an enhanced version of attemptHealing that uses KB
   328→func (kr *KBTransflowRunner) attemptHealingWithKB(ctx context.Context, repoPath string, buildError string) (*TransflowHealingSummary, error) {
   329→	summary := &TransflowHealingSummary{
   330→		Enabled:       true,
   331→		AttemptsCount: 1,
   332→	}
   333→
   334→	// Detect language from build error
   335→	language := DetectLanguageFromBuildError(buildError)
   336→
   337→	// Load KB context
   338→	kbCtx, err := kr.kb.LoadKBContext(ctx, language, []byte(""), []byte(buildError))
   339→	if err != nil {
   340→		// Continue without KB if loading fails
   341→		kbCtx = &KBContext{HasData: false}
   342→	}
   343→
   344→	// Create KB-enhanced job helper
   345→	originalHelper := NewJobSubmissionHelper(kr.jobSubmitter)
   346→	jobHelper := NewExtendedJobSubmissionHelper(originalHelper, kr.kb)
   347→
   348→	// Submit planner job (may use KB suggestions directly)
   349→	planResult, err := jobHelper.SubmitPlannerJob(ctx, kr.config, buildError, kr.workspaceDir)
   350→	if err != nil {
   351→		return summary, fmt.Errorf("planner job failed: %w", err)
   352→	}
   353→
   354→	summary.PlanID = planResult.PlanID
   355→
   356→	// Convert planner options to branch specs
   357→	var branches []BranchSpec
   358→	for i, option := range planResult.Options {
   359→		branchID := fmt.Sprintf("option-%d", i)
   360→		if id, ok := option["id"].(string); ok {
   361→			branchID = id
   362→		}
   363→
   364→		branchType := "llm-exec" // default
   365→		if t, ok := option["type"].(string); ok {
   366→			branchType = t
   367→		}
   368→
   369→		branches = append(branches, BranchSpec{
   370→			ID:     branchID,
   371→			Type:   branchType,
   372→			Inputs: option,
   373→		})
   374→	}
   375→
   376→	// Execute fanout orchestration
   377→	orchestrator := NewFanoutOrchestrator(kr.jobSubmitter)
   378→	maxParallel := 3
   379→	if kr.config.SelfHeal.MaxRetries > 0 {
   380→		maxParallel = kr.config.SelfHeal.MaxRetries
   381→	}
   382→
   383→	winner, allResults, err := orchestrator.RunHealingFanout(ctx, nil, branches, maxParallel)
   384→	summary.AllResults = allResults
   385→
   386→	if err != nil {
   387→		summary.Winner = nil
   388→	} else {
   389→		summary.Winner = &winner
   390→	}
   391→
   392→	// Submit reducer job
   393→	nextAction, reducerErr := jobHelper.SubmitReducerJob(ctx, planResult.PlanID, allResults, summary.Winner, kr.workspaceDir)
   394→	if reducerErr != nil {
   395→		return summary, fmt.Errorf("reducer job failed: %w", reducerErr)
   396→	}
   397→
   398→	// Write KB cases for all attempts
   399→	for _, result := range allResults {
   400→		attempt := kr.convertBranchResultToAttempt(result)
   401→		outcome := kr.convertBranchResultToOutcome(result)
   402→
   403→		// Write the case (non-blocking)
   404→		go func(a *HealingAttempt, o *HealingOutcome) {
   405→			kr.kb.WriteHealingCase(context.Background(), kbCtx, a, o, buildError, "")
   406→		}(attempt, outcome)
   407→	}
   408→
   409→	// Check final result
   410→	if nextAction.Action == "stop" && summary.Winner != nil {
   411→		summary.SetFinalResult(true)
   412→		return summary, nil
   413→	}
   414→
   415→	return summary, fmt.Errorf("healing failed: %s", nextAction.Notes)
   416→}
